class ImageFolderDataset(Dataset):
    def __init__(self, root: str, train: bool, image_size: int = 224):
        if datasets is None or transforms is None:
            raise RuntimeError("torchvision is required for ImageFolder dataset support.")
        tfm_train = transforms.Compose(
            [
                transforms.RandomResizedCrop(image_size),
                transforms.RandomHorizontalFlip(),
                transforms.ToTensor(),
                transforms.Normalize(mean=(0.485, 0.456, 0.406), std=(0.229, 0.224, 0.225)),
            ]
        )
        tfm_eval = transforms.Compose(
            [
                transforms.Resize(int(image_size * 256 / 224)),
                transforms.CenterCrop(image_size),
                transforms.ToTensor(),
                transforms.Normalize(mean=(0.485, 0.456, 0.406), std=(0.229, 0.224, 0.225)),
            ]
        )
        split = "train" if train else "val"
        path = os.path.join(root, split)
        self.ds = datasets.ImageFolder(path, transform=(tfm_train if train else tfm_eval))

    def __len__(self) -> int:
        return len(self.ds)

    def __getitem__(self, idx: int):
        return self.ds[idx]


class RandomClassificationDataset(Dataset):
    def __init__(self, n: int, num_classes: int, image_size: int = 224, channels: int = 3):
        self.n = n
        self.num_classes = num_classes
        self.image_size = image_size
        self.channels = channels

    def __len__(self) -> int:
        return self.n

    def __getitem__(self, idx: int):
        x = torch.rand(self.channels, self.image_size, self.image_size)
        y = torch.randint(0, self.num_classes, (1,)).item()
        return x, y


def build_model(model_name: str, num_classes: int, pretrained: bool = False) -> nn.Module:
    if tv_models is None:
        raise RuntimeError("torchvision is required for model zoo support.")
    if not hasattr(tv_models, model_name):
        raise ValueError(f"Unknown torchvision model: {model_name}")
