def freeze_backbone(model: nn.Module, train_head_only: bool) -> None:
    if not train_head_only:
        return
    for p in model.parameters():
        p.requires_grad = False

    head_params = []
    if hasattr(model, "fc") and isinstance(model.fc, nn.Module):
        head_params = list(model.fc.parameters())
    elif hasattr(model, "classifier") and isinstance(model.classifier, nn.Module):
        head_params = list(model.classifier.parameters())

    if not head_params:
        raise RuntimeError("Could not identify classification head parameters to unfreeze")

    for p in head_params:
        p.requires_grad = True


@torch.no_grad()
def evaluate(model: nn.Module, loader: DataLoader, device: torch.device) -> Dict[str, float]:
    model.eval()
    total = 0
    correct = 0
    loss_sum = 0.0
    crit = nn.CrossEntropyLoss()
    for x, y in loader:
        x = x.to(device, non_blocking=True)
        y = y.to(device, non_blocking=True)
        logits = model(x)
        loss = crit(logits, y)
        loss_sum += float(loss.item()) * x.size(0)
        pred = logits.argmax(dim=1)
        correct += int((pred == y).sum().item())
        total += int(x.size(0))
    return {"loss": loss_sum / max(1, total), "acc": correct / max(1, total)}


def train(
    model: nn.Module,
    train_loader: DataLoader,
    val_loader: Optional[DataLoader],
    device: torch.device,
    epochs: int,
    lr: float,
    weight_decay: float,
    amp: bool,
    grad_clip: float,
    out_path: Optional[str],
) -> Dict[str, Any]:
    crit = nn.CrossEntropyLoss()
    params = [p for p in model.parameters() if p.requires_grad]
    opt = optim.AdamW(params, lr=lr, weight_decay=weight_decay)
    scaler = torch.amp.GradScaler(enabled=amp)

    best = {"val_acc": -1.0, "epoch": -1, "path": None}
    history = []

    model.to(device)

    for ep in range(1, epochs + 1):
        model.train()
        t0 = time.time()
        total = 0
        correct = 0
        loss_sum = 0.0

        for x, y in train_loader:
            x = x.to(device, non_blocking=True)
            y = y.to(device, non_blocking=True)

            opt.zero_grad(set_to_none=True)
            with torch.amp.autocast(device_type=device.type, enabled=amp):
                logits = model(x)
                loss = crit(logits, y)

            scaler.scale(loss).backward()
            if grad_clip > 0:
                scaler.unscale_(opt)
                nn.utils.clip_grad_norm_(params, grad_clip)
            scaler.step(opt)
            scaler.update()

            loss_sum += float(loss.item()) * x.size(0)
            pred = logits.argmax(dim=1)
            correct += int((pred == y).sum().item())
            total += int(x.size(0))

        train_metrics = {"loss": loss_sum / max(1, total), "acc": correct / max(1, total)}
        val_metrics = None
        if val_loader is not None:
            val_metrics = evaluate(model, val_loader, device)

        record = {
            "epoch": ep,
            "train": train_metrics,
            "val": val_metrics,
            "sec": time.time() - t0,
        }
        history.append(record)

        if val_metrics is not None and val_metrics["acc"] > best["val_acc"]:
            best["val_acc"] = float(val_metrics["acc"])
            best["epoch"] = ep
            if out_path:
                os.makedirs(os.path.dirname(out_path) or ".", exist_ok=True)
                torch.save({"model_state_dict": model.state_dict(), "epoch": ep, "val": val_metrics}, out_path)
                best["path"] = out_path

    return {"best": best, "history": history}


def build_loaders(
    dataset_type: str,
    data_root: Optional[str],
    image_size: int,
    batch_size: int,
    workers: int,
    num_classes: int,
) -> Tuple[DataLoader, Optional[DataLoader]]:
    pin = torch.cuda.is_available()
    if dataset_type == "imagefolder":
        if data_root is None:
            raise ValueError("data_root is required for imagefolder dataset")
        train_ds = ImageFolderDataset(data_root, train=True, image_size=image_size)
        val_dir = os.path.join(data_root, "val")
        val_ds = ImageFolderDataset(data_root, train=False, image_size=image_size) if os.path.isdir(val_dir) else None
    elif dataset_type == "random":
        train_ds = RandomClassificationDataset(n=2048, num_classes=num_classes, image_size=image_size)
        val_ds = RandomClassificationDataset(n=256, num_classes=num_classes, image_size=image_size)
    else:
        raise ValueError(f"Unknown dataset_type: {dataset_type}")

    train_loader = DataLoader(
        train_ds,
        batch_size=batch_size,
        shuffle=True,
        num_workers=workers,
        pin_memory=pin,
        drop_last=False,
    )
    val_loader = (
        DataLoader(val_ds, batch_size=batch_size, shuffle=False, num_workers=workers, pin_memory=pin)
        if val_ds is not None
        else None
    )
    return train_loader, val_loader


def parse_kv_json(s: Optional[str]) -> Optional[dict]:
    if not s:
        return None
    s = s.strip()
    if not s:
        return None
    return json.loads(s)


def main(argv: Optional[List[str]] = None) -> int:
    p = argparse.ArgumentParser(description="Download torch checkpoints from URLs and fine-tune on custom datasets.")
    p.add_argument("--url", type=str, required=True, help="Public URL to a torch.save() checkpoint (.pt/.pth).")
    p.add_argument("--cache-dir", type=str, default="./model_cache")
    p.add_argument("--filename", type=str, default=None)
    p.add_argument("--sha256", type=str, default=None)
    p.add_argument("--timeout", type=int, default=60)
    p.add_argument("--overwrite", action="store_true")

    p.add_argument("--model", type=str, default="resnet18", help="torchvision model name")
    p.add_argument("--num-classes", type=int, default=0, help="If 0, infer from ImageFolder.")
    p.add_argument("--checkpoint-key", type=str, default=None, help="Key inside checkpoint holding state_dict.")
    p.add_argument("--drop-prefix", type=str, default=None, help="Drop prefix from checkpoint keys (e.g., 'module.').")
    p.add_argument("--strict", action="store_true", help="Strict load state_dict (not recommended for transfer).")
    p.add_argument("--no-partial-head", action="store_true", help="Do not filter mismatched head layers.")

    p.add_argument("--dataset", type=str, default="imagefolder", choices=["imagefolder", "random"])
    p.add_argument("--data-root", type=str, default=None, help="Root with train/ and optionally val/ subfolders.")
    p.add_argument("--image-size", type=int, default=224)
    p.add_argument("--batch-size", type=int, default=32)
    p.add_argument("--workers", type=int, default=4)

    p.add_argument("--epochs", type=int, default=5)
    p.add_argument("--lr", type=float, default=3e-4)
    p.add_argument("--weight-decay", type=float, default=1e-4)
    p.add_argument("--train-head-only", action="store_true")
    p.add_argument("--amp", action="store_true")
    p.add_argument("--grad-clip", type=float, default=0.0)

    p.add_argument("--device", type=str, default="cuda" if torch.cuda.is_available() else "cpu")
    p.add_argument("--seed", type=int, default=1337)
    p.add_argument("--out", type=str, default="./finetuned.pt")
    p.add_argument("--log-json", type=str, default=None, help="Write training history to this JSON file.")

    args = p.parse_args(argv)

    set_seed(args.seed)
    device = torch.device(args.device)

    if args.dataset == "imagefolder" and args.num_classes == 0:
        if args.data_root is None:
            raise ValueError("--data-root is required when --num-classes 0 and dataset=imagefolder")
        num_classes = infer_num_classes_from_imagefolder(args.data_root)
    else:
        if args.num_classes <= 0:
            raise ValueError("--num-classes must be > 0 for dataset=random or when not inferring")
        num_classes = args.num_classes

    train_loader, val_loader = build_loaders(
        dataset_type=args.dataset,
        data_root=args.data_root,
        image_size=args.image_size,
        batch_size=args.batch_size,
        workers=args.workers,
        num_classes=num_classes,
    )

    model = build_model(args.model, num_classes=num_classes, pretrained=False)

    ckpt = torch_load_from_url(
        url=args.url,
        map_location="cpu",
        cache_dir=args.cache_dir,
        filename=args.filename,
        expected_sha256=args.sha256,
        timeout=args.timeout,
        overwrite=args.overwrite,
    )

    load_info = load_checkpoint_into_model(
        model=model,
        checkpoint=ckpt,
        strict=args.strict,
        key=args.checkpoint_key,
        drop_prefix=args.drop_prefix,
        allow_partial_head=(not args.no_partial_head),
    )

    freeze_backbone(model, train_head_only=args.train_head_only)

    result = train(
        model=model,
        train_loader=train_loader,
        val_loader=val_loader,
        device=device,
        epochs=args.epochs,
        lr=args.lr,
        weight_decay=args.weight_decay,
        amp=args.amp,
        grad_clip=args.grad_clip,
        out_path=args.out,
    )

    summary = {
        "download_url": args.url,
        "cache_dir": args.cache_dir,
        "checkpoint_loaded": True,
        "load_info": load_info,
        "model": args.model,
        "num_classes": num_classes,
        "train_head_only": bool(args.train_head_only),
        "best": result["best"],
        "final": result["history"][-1] if result["history"] else None,
    }

    if args.log_json:
        os.makedirs(os.path.dirname(args.log_json) or ".", exist_ok=True)
        with open(args.log_json, "w", encoding="utf-8") as f:
            json.dump({"summary": summary, "history": result["history"]}, f, indent=2)

    print(json.dumps(summary, indent=2))
    return 0


